def next_grapheme_size(string) when is_binary(string) do
  case :unicode_util.gc(string) do
    [gc] -> {grapheme_byte_size(gc), <<>>}
    [gc, rest] -> {grapheme_byte_size(gc), rest}
    [gc | rest] -> {grapheme_byte_size(gc), rest}
    [] -> nil
    {:error, <<_, rest::bits>>} -> {1, rest}
  end
end

