def via_name(key) do
  {:via, Registry, {__MODULE__, key}}
end

def get_edges(data) do
  case data do
    %{"data" => %{"nearest" => %{"edges" => edges}}} -> {:ok, edges}
    _ -> {:error, :bad_format}
  end
end

def get_stop(edge) do
  case edge do
    %{"node" => %{"place" => stop}} -> {:ok, stop}
    _ -> {:error, :bad_format}
  end
end

def parse_edges(edges) do
  edges
  |> Enum.reduce({:ok, []}, fn
    edge, {:ok, reversed_stops} ->
      with {:ok, stop} <- get_stop(edge),
           {:ok, stop} <- parse_stop(stop) do
        {:ok, [stop | reversed_stops]}
      else
        :ignore -> {:ok, reversed_stops}
        {:error, error} -> {:error, error}
      end

    _edge, {:error, error} ->
      {:error, error}
  end)
  |> case do
    {:ok, reversed_stops} -> {:ok, Enum.reverse(reversed_stops)}
    {:error, error} -> {:error, error}
  end
end

